@@ -0,0 +1,748 @@
+:root {
+  --bg0: #0b0f12;
+  --bg1: #101722;
+  --panel: rgba(16, 22, 30, 0.9);
+  --paper: #f7f2e7;
+  --ink: #0b0f12;
+  --fg0: rgba(247, 242, 231, 0.96);
+  --fg1: rgba(247, 242, 231, 0.72);
+  --fg2: rgba(247, 242, 231, 0.52);
+  --line: rgba(247, 242, 231, 0.12);
+  --shadow: 0 36px 90px rgba(0, 0, 0, 0.5);
+  --shadow2: 0 14px 40px rgba(0, 0, 0, 0.35);
+
+  --accent: #b8ff5a;
+  --accent2: #ff9b35;
+  --accent3: #36c9b9;
+
+  --r: 18px;
+  --r2: 28px;
+  --max: 1120px;
+
+  --display: "Fraunces", "Iowan Old Style", "Palatino Linotype", serif;
+  --body: "IBM Plex Sans", "Segoe UI", sans-serif;
+  --mono:
+    "IBM Plex Mono", "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas,
+    "Liberation Mono", "Courier New", monospace;
+}
+
+@media (prefers-color-scheme: light) {
+  :root {
+    --bg0: #fbf6eb;
+    --bg1: #f1ecdf;
+    --panel: rgba(255, 255, 255, 0.86);
+    --paper: #0b0f12;
+    --ink: #0b0f12;
+    --fg0: rgba(9, 12, 16, 0.92);
+    --fg1: rgba(9, 12, 16, 0.7);
+    --fg2: rgba(9, 12, 16, 0.5);
+    --line: rgba(9, 12, 16, 0.14);
+    --shadow: 0 26px 70px rgba(9, 12, 16, 0.12);
+    --shadow2: 0 10px 26px rgba(9, 12, 16, 0.1);
+  }
+}
+
+* {
+  box-sizing: border-box;
+}
+
+html,
+body {
+  height: 100%;
+}
+
+body {
+  margin: 0;
+  color: var(--fg0);
+  background:
+    radial-gradient(800px 520px at 10% -20%, rgba(184, 255, 90, 0.2), transparent 60%),
+    radial-gradient(740px 520px at 100% 0%, rgba(255, 155, 53, 0.18), transparent 60%),
+    radial-gradient(900px 600px at 80% 100%, rgba(54, 201, 185, 0.18), transparent 55%),
+    linear-gradient(180deg, var(--bg0), var(--bg1));
+  font-family: var(--body);
+  letter-spacing: 0.01em;
+  line-height: 1.6;
+}
+
+body::before {
+  content: "";
+  position: fixed;
+  inset: 0;
+  pointer-events: none;
+  opacity: 0.18;
+  background-image:
+    linear-gradient(rgba(255, 255, 255, 0.04) 1px, transparent 1px),
+    linear-gradient(90deg, rgba(255, 255, 255, 0.04) 1px, transparent 1px);
+  background-size: 40px 40px;
+  mix-blend-mode: soft-light;
+}
+
+a {
+  color: inherit;
+  text-decoration: none;
+}
+
+a:hover {
+  text-decoration: underline;
+  text-decoration-thickness: 2px;
+  text-underline-offset: 4px;
+}
+
+.shell {
+  position: relative;
+  margin: 0 auto;
+  max-width: var(--max);
+  padding: 30px 18px 80px;
+}
+
+.top {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: 12px;
+  padding: 10px 6px 16px;
+}
+
+.brand {
+  display: inline-flex;
+  align-items: center;
+  gap: 10px;
+  text-decoration: none;
+}
+
+.brand:hover {
+  text-decoration: none;
+}
+
+.brand__mark {
+  width: 34px;
+  height: 34px;
+  border-radius: 12px;
+  display: grid;
+  place-items: center;
+  background:
+    radial-gradient(circle at 30% 30%, rgba(184, 255, 90, 0.92), transparent 60%),
+    radial-gradient(circle at 70% 20%, rgba(255, 155, 53, 0.7), transparent 60%),
+    radial-gradient(circle at 20% 80%, rgba(54, 201, 185, 0.65), transparent 60%),
+    rgba(255, 255, 255, 0.08);
+  border: 1px solid var(--line);
+  box-shadow: var(--shadow2);
+  font-family: var(--display);
+  font-weight: 700;
+  letter-spacing: -0.02em;
+}
+
+.brand__word {
+  font-family: var(--display);
+  font-weight: 700;
+  letter-spacing: 0.02em;
+  font-size: 18px;
+}
+
+.nav {
+  display: flex;
+  align-items: center;
+  gap: 10px;
+}
+
+.nav a {
+  padding: 8px 12px;
+  border-radius: 999px;
+  border: 1px solid transparent;
+  color: var(--fg1);
+  font-family: var(--mono);
+  font-size: 12px;
+  letter-spacing: 0.08em;
+  text-transform: uppercase;
+}
+
+.nav a:hover {
+  text-decoration: none;
+  color: var(--fg0);
+  border-color: var(--line);
+  background: rgba(255, 255, 255, 0.05);
+}
+
+.nav a[aria-current="page"] {
+  color: var(--fg0);
+  border-color: rgba(184, 255, 90, 0.5);
+  background: rgba(184, 255, 90, 0.1);
+}
+
+.hero {
+  padding: 10px 6px 0;
+}
+
+.hero__frame {
+  position: relative;
+  border-radius: var(--r2);
+  border: 1px solid var(--line);
+  background: var(--panel);
+  box-shadow: var(--shadow);
+  overflow: hidden;
+  display: grid;
+  grid-template-columns: 1.1fr 0.9fr;
+  gap: 20px;
+  padding: 26px;
+}
+
+.hero__frame::after {
+  content: "";
+  position: absolute;
+  inset: 0;
+  background: linear-gradient(140deg, rgba(184, 255, 90, 0.08), transparent 40%);
+  pointer-events: none;
+}
+
+.hero__copy {
+  position: relative;
+  z-index: 1;
+}
+
+.kicker {
+  margin: 0 0 12px;
+  color: var(--fg2);
+  font-family: var(--mono);
+  font-size: 12px;
+  letter-spacing: 0.18em;
+  text-transform: uppercase;
+}
+
+.title {
+  margin: 0;
+  font-family: var(--display);
+  font-size: clamp(32px, 5vw, 52px);
+  font-weight: 700;
+  letter-spacing: -0.015em;
+  line-height: 1.05;
+}
+
+.lede {
+  margin: 14px 0 0;
+  color: var(--fg1);
+  font-size: 18px;
+  max-width: 58ch;
+}
+
+.lede strong {
+  color: var(--fg0);
+  font-weight: 600;
+}
+
+.ctaRow {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 10px;
+  margin-top: 18px;
+}
+
+.btn {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  gap: 10px;
+  padding: 11px 16px;
+  border-radius: 14px;
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.04);
+  color: var(--fg0);
+  font-family: var(--mono);
+  font-size: 12px;
+  letter-spacing: 0.08em;
+  text-transform: uppercase;
+  cursor: pointer;
+}
+
+.btn:hover {
+  text-decoration: none;
+  background: rgba(255, 255, 255, 0.08);
+}
+
+.btn--primary {
+  border-color: rgba(184, 255, 90, 0.5);
+  background: rgba(184, 255, 90, 0.12);
+}
+
+.btn--ghost {
+  border-color: rgba(255, 155, 53, 0.5);
+  background: rgba(255, 155, 53, 0.12);
+}
+
+.quickRow {
+  margin-top: 22px;
+  padding: 14px;
+  border-radius: 16px;
+  border: 1px solid var(--line);
+  background: rgba(0, 0, 0, 0.2);
+  display: grid;
+  gap: 10px;
+}
+
+.quickRow__label {
+  font-family: var(--mono);
+  font-size: 12px;
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+  color: var(--fg2);
+}
+
+.quickRow__code {
+  display: grid;
+  gap: 6px;
+  font-family: var(--mono);
+  font-size: 13px;
+  color: var(--fg0);
+}
+
+.quickRow__code code {
+  display: block;
+  padding: 8px 10px;
+  border-radius: 12px;
+  background: rgba(0, 0, 0, 0.35);
+  border: 1px solid rgba(255, 255, 255, 0.08);
+}
+
+.quickRow__actions {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 8px;
+}
+
+.hero__visual {
+  position: relative;
+  z-index: 1;
+  display: grid;
+  gap: 14px;
+}
+
+.shot {
+  margin: 0;
+  border-radius: 20px;
+  border: 1px solid rgba(255, 255, 255, 0.12);
+  background: rgba(0, 0, 0, 0.24);
+  overflow: hidden;
+  box-shadow: var(--shadow2);
+}
+
+.shot img {
+  display: block;
+  width: 100%;
+  height: auto;
+}
+
+.shot figcaption {
+  padding: 10px 12px;
+  font-family: var(--mono);
+  font-size: 12px;
+  color: var(--fg2);
+  border-top: 1px solid rgba(255, 255, 255, 0.08);
+}
+
+.shot--ext {
+  transform: translateX(18px);
+}
+
+.productGrid {
+  display: grid;
+  grid-template-columns: repeat(2, minmax(0, 1fr));
+  gap: 18px;
+  margin-top: 24px;
+  padding: 0 6px;
+}
+
+.productCard {
+  border-radius: var(--r2);
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.03);
+  padding: 20px 18px;
+  box-shadow: var(--shadow2);
+}
+
+.productCard__head {
+  display: grid;
+  gap: 10px;
+  margin-bottom: 12px;
+}
+
+.productCard h2 {
+  margin: 0;
+  font-family: var(--display);
+  font-weight: 700;
+  letter-spacing: -0.01em;
+  font-size: 22px;
+}
+
+.productCard p {
+  margin: 0;
+  color: var(--fg1);
+}
+
+.badge {
+  align-self: start;
+  display: inline-flex;
+  align-items: center;
+  gap: 8px;
+  padding: 6px 10px;
+  border-radius: 999px;
+  border: 1px solid rgba(184, 255, 90, 0.4);
+  background: rgba(184, 255, 90, 0.14);
+  font-family: var(--mono);
+  font-size: 11px;
+  letter-spacing: 0.1em;
+  text-transform: uppercase;
+}
+
+.badge--alt {
+  border-color: rgba(255, 155, 53, 0.5);
+  background: rgba(255, 155, 53, 0.14);
+}
+
+.list {
+  margin: 12px 0 0 16px;
+  color: var(--fg1);
+}
+
+.list li {
+  margin: 6px 0;
+}
+
+.cardCode {
+  margin-top: 14px;
+  border-radius: 16px;
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  background: rgba(0, 0, 0, 0.35);
+}
+
+pre {
+  margin: 0;
+  padding: 14px 14px 12px;
+  color: rgba(247, 242, 231, 0.94);
+  font-family: var(--mono);
+  font-size: 12.5px;
+  line-height: 1.6;
+  overflow-x: auto;
+}
+
+code {
+  font-family: var(--mono);
+}
+
+.steps {
+  margin: 12px 0 0 18px;
+  color: var(--fg1);
+}
+
+.steps li {
+  margin: 6px 0;
+}
+
+.callout {
+  margin-top: 12px;
+  padding: 12px;
+  border-radius: 14px;
+  border: 1px dashed rgba(54, 201, 185, 0.5);
+  background: rgba(54, 201, 185, 0.08);
+  color: var(--fg1);
+}
+
+.capGrid {
+  display: grid;
+  grid-template-columns: repeat(4, minmax(0, 1fr));
+  gap: 14px;
+  margin-top: 22px;
+  padding: 0 6px;
+}
+
+.capCard {
+  border-radius: 18px;
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.03);
+  padding: 16px;
+  box-shadow: var(--shadow2);
+}
+
+.capCard__eyebrow {
+  font-family: var(--mono);
+  font-size: 11px;
+  letter-spacing: 0.18em;
+  text-transform: uppercase;
+  color: var(--fg2);
+}
+
+.capCard h3 {
+  margin: 8px 0 6px;
+  font-family: var(--display);
+  font-size: 18px;
+}
+
+.capCard p {
+  margin: 0;
+  color: var(--fg1);
+}
+
+.flow {
+  margin-top: 24px;
+  padding: 0 6px;
+}
+
+.flow__card {
+  border-radius: var(--r2);
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.03);
+  padding: 20px;
+  box-shadow: var(--shadow2);
+}
+
+.flow__card h2 {
+  margin: 0 0 16px;
+  font-family: var(--display);
+  font-size: 24px;
+}
+
+.flow__steps {
+  display: grid;
+  gap: 12px;
+}
+
+.flowStep {
+  display: grid;
+  grid-template-columns: 48px 1fr;
+  gap: 12px;
+  align-items: start;
+  padding: 12px;
+  border-radius: 16px;
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  background: rgba(0, 0, 0, 0.2);
+}
+
+.flowStep__num {
+  font-family: var(--mono);
+  font-size: 16px;
+  letter-spacing: 0.12em;
+  color: var(--fg2);
+}
+
+.flowStep h4 {
+  margin: 0 0 4px;
+  font-family: var(--display);
+  font-size: 18px;
+}
+
+.flowStep p {
+  margin: 0;
+  color: var(--fg1);
+}
+
+.more {
+  margin-top: 24px;
+  padding: 0 6px;
+}
+
+.more__card {
+  border-radius: var(--r2);
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.03);
+  padding: 20px;
+  box-shadow: var(--shadow2);
+}
+
+.more__card h2 {
+  margin: 0 0 14px;
+  font-family: var(--display);
+  font-size: 22px;
+}
+
+.more__grid {
+  display: grid;
+  grid-template-columns: repeat(3, minmax(0, 1fr));
+  gap: 10px;
+}
+
+.moreLink {
+  display: block;
+  padding: 10px 12px;
+  border-radius: 12px;
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  background: rgba(0, 0, 0, 0.2);
+  font-family: var(--mono);
+  font-size: 12px;
+  letter-spacing: 0.06em;
+  text-transform: uppercase;
+  color: var(--fg1);
+}
+
+.moreLink:hover {
+  text-decoration: none;
+  color: var(--fg0);
+  border-color: rgba(184, 255, 90, 0.4);
+}
+
+.footer {
+  margin-top: 30px;
+  padding: 18px 6px 0;
+  border-top: 1px solid var(--line);
+  display: flex;
+  flex-wrap: wrap;
+  align-items: baseline;
+  justify-content: space-between;
+  gap: 10px;
+  color: var(--fg2);
+  font-family: var(--mono);
+  font-size: 12px;
+}
+
+.footer a {
+  color: var(--fg1);
+}
+
+.reveal {
+  opacity: 0;
+  transform: translateY(14px);
+}
+
+.reveal.is-on {
+  opacity: 1;
+  transform: translateY(0);
+  transition:
+    opacity 700ms cubic-bezier(0.2, 0.9, 0.2, 1),
+    transform 700ms cubic-bezier(0.2, 0.9, 0.2, 1);
+}
+
+.hero--compact .hero__frame {
+  max-width: 760px;
+  margin: 30px auto 0;
+  grid-template-columns: 1fr;
+}
+
+.docShell {
+  display: grid;
+  grid-template-columns: 260px 1fr;
+  gap: 18px;
+  padding: 10px 6px 0;
+}
+
+.side {
+  position: sticky;
+  top: 14px;
+  align-self: start;
+  border-radius: var(--r2);
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.03);
+  padding: 14px 12px;
+  box-shadow: var(--shadow2);
+}
+
+.side h2 {
+  margin: 0 0 10px;
+  font-family: var(--mono);
+  font-size: 12px;
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+  color: var(--fg2);
+}
+
+.side a {
+  display: block;
+  padding: 9px 10px;
+  border-radius: 12px;
+  border: 1px solid transparent;
+  color: var(--fg1);
+  font-family: var(--mono);
+  font-size: 12px;
+}
+
+.side a:hover {
+  text-decoration: none;
+  border-color: var(--line);
+  background: rgba(255, 255, 255, 0.04);
+  color: var(--fg0);
+}
+
+.side a[aria-current="page"] {
+  border-color: rgba(184, 255, 90, 0.4);
+  background: rgba(184, 255, 90, 0.1);
+  color: var(--fg0);
+}
+
+.doc {
+  border-radius: var(--r2);
+  border: 1px solid var(--line);
+  background: rgba(255, 255, 255, 0.03);
+  box-shadow: var(--shadow);
+  padding: 18px 18px 14px;
+}
+
+.doc h1 {
+  margin: 0 0 10px;
+  font-family: var(--display);
+  font-weight: 700;
+  letter-spacing: -0.015em;
+  font-size: 30px;
+}
+
+.doc h2 {
+  margin: 18px 0 8px;
+  font-family: var(--display);
+  font-weight: 650;
+  letter-spacing: -0.01em;
+  font-size: 20px;
+}
+
+.doc ul {
+  margin: 8px 0 0 18px;
+  color: var(--fg1);
+}
+
+.doc li {
+  margin: 6px 0;
+}
+
+.doc p {
+  margin: 10px 0 0;
+  color: var(--fg1);
+}
+
+.doc .note {
+  margin-top: 14px;
+  padding: 12px 12px;
+  border-radius: 14px;
+  border: 1px dashed rgba(184, 255, 90, 0.45);
+  background: rgba(184, 255, 90, 0.08);
+  color: var(--fg1);
+}
+
+@media (max-width: 980px) {
+  .hero__frame {
+    grid-template-columns: 1fr;
+  }
+  .shot--ext {
+    transform: none;
+  }
+  .productGrid {
+    grid-template-columns: 1fr;
+  }
+  .capGrid {
+    grid-template-columns: 1fr 1fr;
+  }
+  .more__grid {
+    grid-template-columns: 1fr 1fr;
+  }
+  .docShell {
+    grid-template-columns: 1fr;
+  }
+  .side {
+    position: static;
+  }
+}
+
+@media (max-width: 640px) {
+  .capGrid {
+    grid-template-columns: 1fr;
+  }
+  .more__grid {
+    grid-template-columns: 1fr;
+  }
+  .flowStep {
+    grid-template-columns: 1fr;
+  }
+}

